1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	};
9	
10	function basePremiumFor(item: { type: string }): number {
11	  return BASE_PREMIUM_BY_TYPE[item.type];
12	}
13	
14	export function quote(_customer: { yearsWithMHPCO: number }, items: { type: string }[]): number {
15	  const itemsTotal = items.length === 0 ? 0 : basePremiumFor(items[0]);
16	  return itemsTotal + PROCESSING_FEE;
17	}
18	
19	export function claim(): number {
20	  return undefined as unknown as number;
21	}
